    bufferSolutions: {
        composition: {
            acidBuffer:  "Weak acid + its conjugate base (e.g. CHвӮғCOOH + CHвӮғCOOвҒ»NaвҒә) вҖ” resists pH change in the acidic range",
            alkalineBuffer: "Weak base + its conjugate acid (e.g. NHвӮғ + NHвӮ„Cl) вҖ” resists pH change in the alkaline range"
        },
        mechanism: {
            addAcid: {
                description: "When HвҒә is added, the conjugate base (AвҒ») neutralises it: AвҒ» + HвҒә вҶ’ HA. The equilibrium shifts to the left, consuming HвҒә and forming more weak acid. [HвҒә] barely changes because AвҒ» is present in large reservoir.",
                equation:    "CHвӮғCOOвҒ» + HвҒә вҶ’ CHвӮғCOOH"
            },
            addAlkali: {
                description: "When OHвҒ» is added, the weak acid neutralises it: HA + OHвҒ» вҶ’ AвҒ» + HвӮӮO. The equilibrium shifts to the right, consuming OHвҒ». [OHвҒ»] barely changes because HA is present in large reservoir.",
                equation:    "CHвӮғCOOH + OHвҒ» вҶ’ CHвӮғCOOвҒ» + HвӮӮO"
            },
            whyResists: "The buffer resists pH change because both a proton donor (HA) and proton acceptor (AвҒ») are simultaneously present in comparable concentrations. Neither added HвҒә nor added OHвҒ» escapes neutralisation."
        },
        hendersonHasselbalch: {
            equation:     "pH = pKa + logвӮҒвӮҖ([AвҒ»]/[HA])",
            derivation:   "From Ka = [HвҒә][AвҒ»]/[HA], rearrange: [HвҒә] = Ka Г— [HA]/[AвҒ»]. Take вҲ’logвӮҒвӮҖ of both sides: pH = pKa вҲ’ log([HA]/[AвҒ»]) = pKa + log([AвҒ»]/[HA]).",
            halfEquivalencePoint: "When [AвҒ»] = [HA], log(1) = 0, so pH = pKa. At the half-equivalence point of a weak acid titration, pH = pKa of the weak acid.",
            workedExample: {
                title: "Calculating Buffer pH Using the HendersonвҖ“Hasselbalch Equation",
                problem: "A buffer is prepared by dissolving 0.400 mol of sodium ethanoate (CHвӮғCOONa) and 0.600 mol of ethanoic acid (CHвӮғCOOH) in water to make 1.00 dmВі of solution. Calculate the pH of this buffer. Ka(CHвӮғCOOH) = 1.74 Г— 10вҒ»вҒө mol dmвҒ»Ві.",
                steps: [
                    {
                        step: 1,
                        action: "Identify [AвҒ»] and [HA]",
                        working: "[CHвӮғCOOвҒ»] = 0.400 mol dmвҒ»Ві (from sodium ethanoate, fully dissociates)\n[CHвӮғCOOH] = 0.600 mol dmвҒ»Ві",
                        result: "[AвҒ»] = 0.400, [HA] = 0.600 mol dmвҒ»Ві"
                    },
                    {
                        step: 2,
                        action: "Calculate pKa",
                        working: "pKa = вҲ’logвӮҒвӮҖ(1.74 Г— 10вҒ»вҒө) = 4.76",
                        result: "pKa = 4.76"
                    },
                    {
                        step: 3,
                        action: "Apply HendersonвҖ“Hasselbalch",
                        working: "pH = pKa + log([AвҒ»]/[HA]) = 4.76 + log(0.400/0.600) = 4.76 + log(0.667) = 4.76 + (вҲ’0.176)",
                        result: "pH = 4.76 вҲ’ 0.176 = 4.58"
                    }
                ],
                answer: "pH = 4.58",
                commonError: "Inverting the ratio вҖ” writing log([HA]/[AвҒ»]) instead of log([AвҒ»]/[HA]). The HendersonвҖ“Hasselbalch equation always has [AвҒ»] (conjugate base) in the numerator. When [AвҒ»] < [HA], the log term is negative and pH < pKa вҖ” which makes chemical sense (more acid present shifts pH below pKa)."
            }
        }
    },

