            // 10. MISCONCEPTIONS AND COMMON ERRORS
            // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            misconceptionsAndErrors: {
                overview: "Persistent student errors and conceptual traps in dynamic equilibrium",

                commonErrors: [
                    {
                        error: "Thinking equilibrium means reactions have stopped",
                        correction: "At equilibrium, forward and reverse reactions are still occurring at equal rates вҖ” the 'dynamic' in dynamic equilibrium refers to ongoing molecular change"
                    },
                    {
                        error: "Assuming equal concentrations of reactants and products at equilibrium",
                        correction: "Concentrations are constant at equilibrium, not equal. The ratio is described by K, which may be very large or very small"
                    },
                    {
                        error: "Believing a catalyst shifts the position of equilibrium",
                        correction: "A catalyst speeds up both forward and reverse reactions equally вҖ” equilibrium is reached faster but K and equilibrium concentrations are unchanged"
                    },
                    {
                        error: "Including pure solids/liquids in K expressions",
                        correction: "The concentration of a pure solid or pure liquid is constant and is incorporated into K вҖ” they are omitted from the K expression"
                    },
                    {
                        error: "Confusing rate of reaction with position of equilibrium",
                        correction: "Rate and position are independent. High temperature increases rate but may decrease yield (for exothermic reactions)"
                    },
                    {
                        error: "Thinking changing concentration changes K",
                        correction: "Only temperature changes K. Concentration, pressure, and catalyst changes shift the position but not the value of K"
                    },
                    {
                        error: "Applying Le Chatelier's principle without considering the sign of О”H",
                        correction: "Must know whether the reaction is exothermic or endothermic before predicting the temperature effect on equilibrium position"
                    },
                    {
                        error: "Confusing K_c and K_p",
                        correction: "K_c uses concentrations; K_p uses partial pressures. Related by K_p = K_c(RT)^О”n"
                    }
                ]
            }
