            foundations: {
                overview: "Core vocabulary and conceptual prerequisites for solubility equilibrium",

                dissolution: {
                    definition: "The process by which an ionic solid disperses into its constituent ions in a solvent",
                    generalEquation: "MвӮ“Aбө§(s) вҮҢ xM^n+(aq) + yA^m-(aq)",
                    isHeterogeneousEquilibrium: "Involves two phases: solid and aqueous solution",
                    isSaturated: "Solubility equilibrium applies specifically to saturated solutions вҖ” excess undissolved solid must be present",
                    exampleEquations: [
                        "AgCl(s) вҮҢ AgвҒә(aq) + ClвҒ»(aq)",
                        "BaSOвӮ„(s) вҮҢ BaВІвҒә(aq) + SOвӮ„ВІвҒ»(aq)",
                        "PbIвӮӮ(s) вҮҢ PbВІвҒә(aq) + 2IвҒ»(aq)",
                        "CaвӮғ(POвӮ„)вӮӮ(s) вҮҢ 3CaВІвҒә(aq) + 2POвӮ„ВівҒ»(aq)"
                    ]
                },

                saturatedSolution: {
                    definition: "A solution in which the concentration of dissolved ions is at the maximum possible value at that temperature вҖ” in equilibrium with undissolved solid",
                    condition: "Undissolved solid must be present for true equilibrium",
                    unsaturated: "Q_sp < K_sp: more solid can dissolve; no equilibrium established",
                    saturated: "Q_sp = K_sp: equilibrium established; dissolving rate = crystallisation rate",
                    supersaturated: "Q_sp > K_sp: metastable state; solid will precipitate until Q_sp = K_sp"
                },

                sparinglyVsHighlySoluble: {
                    spariglySoluble: {
                        definition: "Dissolves to give very low ion concentrations at equilibrium",
                        kspRange: "K_sp typically < 10вҒ»вҒҙ",
                        examples: ["AgCl: K_sp = 1.8 Г— 10вҒ»В№вҒ°", "BaSOвӮ„: K_sp = 1.1 Г— 10вҒ»В№вҒ°", "PbIвӮӮ: K_sp = 9.8 Г— 10вҒ»вҒ№"]
                    },
                    highlySoluble: {
                        definition: "Dissolves completely or to high concentration; no equilibrium with solid under normal conditions",
                        examples: ["NaCl: highly soluble", "KNOвӮғ: highly soluble"],
                        note: "K_sp concept is not useful for highly soluble salts вҖ” the solution is far from saturated under normal conditions"
                    },
                    molarSolubilityDefinition: {
                        definition: "The maximum number of moles of a substance that can dissolve in 1 dmВі of solution at a given temperature",
                        symbol: "s (mol dmвҒ»Ві)",
                        relationship: "s is derived from K_sp and stoichiometry of dissolution"
                    }
                },

                heterogeneousEquilibriumReview: {
                    rule: "Pure solids are omitted from K expressions because their concentration (density/molar mass) is constant",
                    application: "The undissolved solid is not included in K_sp вҖ” only the dissolved ions appear",
                    example: "AgCl(s) вҮҢ AgвҒә(aq) + ClвҒ»(aq): K_sp = [AgвҒә][ClвҒ»] (not [AgCl])"
                }
            },

